using System;`nusing System.Collections.Generic;`nusing GestaoManutencao.Core.Enums;`n`nnamespace GestaoManutencao.Core.Domain`n{`n    public class Tecnico`n    {`n        public Guid Id { get; private set; }`n        public string Nome { get; private set; }`n        private readonly List<EspecialidadeTecnica> _especialidades = new List<EspecialidadeTecnica>();`n        public IReadOnlyCollection<EspecialidadeTecnica> Especialidades => _especialidades.AsReadOnly();`n`n        public Tecnico(string nome, List<EspecialidadeTecnica> especialidades)`n        {`n            if (string.IsNullOrWhiteSpace(nome))`n                throw new ArgumentException("Nome do tecnico eh obrigatorio.");`n            if (especialidades == null || especialidades.Count == 0)`n                throw new ArgumentException("O tecnico deve ter pelo menos uma especialidade.");`n`n            Id = Guid.NewGuid();`n            Nome = nome;`n            _especialidades.AddRange(especialidades);`n        }`n`n        public bool PossuiEspecialidade(EspecialidadeTecnica especialidade)`n        {`n            return _especialidades.Contains(specialidade);`n        }`n    }`n}
